#include <iostream>

class Gauge
{
    int m_level{};

public:
    explicit Gauge(int level) : m_level{ level } {}

    int level() const { return m_level; }

    Gauge& operator++()
    {
        ++m_level;
        return *this;
    }

    Gauge& operator--()
    {
        --m_level;
        return *this;
    }
};

int main()
{
    int start{};
    int ups{};
    int downs{};
    std::cin >> start >> ups >> downs;

    Gauge g{ start };

    for (int i{ 0 }; i < ups; ++i)
        ++g;

    std::cout << g.level() << '\n';

    for (int i{ 0 }; i < downs; ++i)
        --g;

    std::cout << g.level() << '\n';

    return 0;
}

