#include <iostream>

class Score
{
    int m_points{};

public:
    explicit Score(int p) : m_points{ p } {}

    int points() const { return m_points; }

    Score& operator++()
    {
        ++m_points;
        return *this;
    }

    Score operator++(int)
    {
        Score old{ *this };
        ++(*this);
        return old;
    }
};

int main()
{
    int initial{};
    int n{};
    std::cin >> initial >> n;

    Score s{ initial };

    for (int i{ 0 }; i < n; ++i)
    {
        Score old{ s++ };
        std::cout << old.points() << ' ' << s.points() << '\n';
    }

    return 0;
}
